import { useEffect, useState } from "react";
import axiosInstance from "../axiosConfig";

const Tasks = () => {
  const [plans, setPlans] = useState([]);
  const [subscriptions, setSubscriptions] = useState([]);
  const [selectedPlan, setSelectedPlan] = useState("");

  const fetchPlans = async () => {
    try {
      const res = await axiosInstance.get("/api/plans");
      setPlans(res.data);
    } catch {
      alert("Failed to load plans");
    }
  };

  const fetchSubscriptions = async () => {
    try {
      const res = await axiosInstance.get("/api/subscriptions");
      setSubscriptions(res.data);
    } catch {
      alert("Failed to load subscriptions");
    }
  };

  const handleSubscribe = async () => {
    if (!selectedPlan) return alert("Select a plan");

    try {
      await axiosInstance.post("/api/subscriptions", {
        plan: selectedPlan,
      });
      fetchSubscriptions();
    } catch {
      alert("Subscription failed");
    }
  };

  const handleDelete = async (id) => {
    try {
      await axiosInstance.delete(`/api/subscriptions/${id}`);
      fetchSubscriptions();
    } catch {
      alert("Failed to cancel");
    }
  };

  useEffect(() => {
    fetchPlans();
    fetchSubscriptions();
  }, []);

  return (
    <div className="page">
      <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
        Subscriptions
      </h2>

      {/* SUBSCRIBE */}
      <div className="card">
        <select
          value={selectedPlan}
          onChange={(e) => setSelectedPlan(e.target.value)}
        >
          <option value="">Select Plan</option>
          {plans.map((p) => (
            <option key={p._id} value={p._id}>
              {p.name} - ${p.price}
            </option>
          ))}
        </select>

        <button className="btn-success" onClick={handleSubscribe}>
          Subscribe
        </button>
      </div>

      {/* LIST */}
      {subscriptions.map((sub) => (
        <div key={sub._id} className="card">
          <div className="row">
            <div>
              <strong>{sub.plan?.name}</strong>
              <p style={{ fontSize: "13px" }}>
                Status: {sub.status}
              </p>
            </div>

            <button
              className="btn-danger btn-inline"
              onClick={() => handleDelete(sub._id)}
            >
              Cancel
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

export default Tasks;
